"use client";

import React, { useState, useEffect } from 'react';

export default function AdminDashboard() {
  const [message, setMessage] = useState('');
  const [status, setStatus] = useState<'idle' | 'sending' | 'success' | 'error'>('idle');
  const [subscriberCount, setSubscriberCount] = useState<number | null>(null);

  // Fetch the real-time count from our new API
  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch('/api/admin/stats');
        const data = await res.json();
        setSubscriberCount(data.activeSubscribers);
      } catch (err) {
        console.error("Failed to load stats");
      }
    };
    fetchStats();
  }, [status]); // Re-fetch after a broadcast is sent

  const handleBroadcast = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!message) return;
    setStatus('sending');
    try {
      const response = await fetch('/api/push/send', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message }),
      });
      if (response.ok) {
        setStatus('success');
        setMessage('');
        setTimeout(() => setStatus('idle'), 3000);
      } else {
        setStatus('error');
      }
    } catch (error) {
      setStatus('error');
    }
  };

  return (
    <main className="min-h-screen bg-black text-white p-10 font-sans">
      <header className="mb-12 border-b border-gray-800 pb-6">
        <h1 className="text-3xl font-black tracking-tighter uppercase">Mission Control</h1>
        <p className="text-gray-500 font-mono text-sm">WhenIsDue // Authority Engine Admin</p>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
        <section className="bg-gray-900 border border-gray-800 p-8 rounded-xl shadow-2xl">
          <h2 className="text-xl font-bold mb-6 flex items-center gap-2">
            <span className="w-3 h-3 bg-blue-500 rounded-full animate-pulse"></span>
            Live Global Broadcast
          </h2>
          <form onSubmit={handleBroadcast} className="space-y-6">
            <textarea 
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Enter alert message..."
              className="w-full bg-black border border-gray-700 rounded-lg p-4 text-white focus:border-blue-500 outline-none h-32"
            />
            <button 
              type="submit"
              disabled={status === 'sending' || !message}
              className={`w-full py-4 rounded-lg font-black uppercase tracking-widest ${
                status === 'success' ? 'bg-green-600' : 'bg-blue-600 hover:bg-blue-500'
              } disabled:opacity-50`}
            >
              {status === 'idle' && "Initialize Broadcast"}
              {status === 'sending' && "Processing..."}
              {status === 'success' && "Broadcast Complete"}
              {status === 'error' && "System Error"}
            </button>
          </form>
        </section>

        <section className="space-y-6">
          <div className="bg-gray-900 border border-gray-800 p-6 rounded-xl">
            <h3 className="text-gray-500 text-xs font-black uppercase mb-2">System Status</h3>
            <div className="text-2xl font-mono text-green-400 uppercase tracking-widest">Connected</div>
          </div>
          <div className="bg-gray-900 border border-gray-800 p-6 rounded-xl">
            <h3 className="text-gray-500 text-xs font-black uppercase mb-2">Active Subscribers</h3>
            <div className="text-5xl font-black">
              {subscriberCount !== null ? subscriberCount : "--"}
            </div>
            <p className="text-gray-600 text-xs mt-3">Verified browser endpoints in SQLite database.</p>
          </div>
        </section>
      </div>
    </main>
  );
}